package com.example.systemoptimization

import android.content.Context
import kotlinx.coroutines.delay

class DataSyncManager(
    private val context: Context
) {
    suspend fun synchronize(syncScope: String?, force: Boolean) {
        when (syncScope ?: "default") {
            "full" -> {
                delay(if (force) 500 else 1000)
            }
            "incremental" -> {
                delay(if (force) 250 else 600)
            }
            else -> {
                delay(if (force) 300 else 700)
            }
        }
    }
}

package com.example.systemoptimization

import android.content.Context
import kotlinx.coroutines.delay

class CleanupManager(
    private val context: Context
) {
    suspend fun cleanup(target: String?, force: Boolean) {
        when (target ?: "temporary") {
            "cache" -> {
                delay(if (force) 200 else 500)
            }
            "logs" -> {
                delay(if (force) 200 else 400)
            }
            "all" -> {
                delay(if (force) 600 else 1200)
            }
            else -> {
                delay(if (force) 250 else 450)
            }
        }
    }
}

